import { Router } from 'express';

export const router = Router();

router.get('/', (req, res) => {
  res.json({ message: 'Welcome to {projectName} API' });
});

router.get('/users', (req, res) => {
  res.json([{ id: 1, name: 'Alice' }, { id: 2, name: 'Bob' }]);
});

export function errorHandler(err, req, res, next) {
  console.error(err.stack);
  res.status(err.status || 500).json({ error: err.message || 'Internal Server Error' });
}

import { describe, it } from 'node:test';
import assert from 'node:assert/strict';
import http from 'node:http';
import express from 'express';
import { router } from '../src/routes/index.js';

function request(app, path) {
  return new Promise((resolve, reject) => {
    const server = app.listen(0, () => {
      const port = server.address().port;
      http.get(`http://127.0.0.1:${port}${path}`, (res) => {
        let body = '';
        res.on('data', (chunk) => { body += chunk; });
        res.on('end', () => {
          server.close();
          resolve({ status: res.statusCode, body: JSON.parse(body) });
        });
      }).on('error', (err) => { server.close(); reject(err); });
    });
  });
}

describe('Health endpoint', () => {
  it('GET /health returns { status: ok }', async () => {
    const app = express();
    app.get('/health', (req, res) => res.json({ status: 'ok' }));
    const res = await request(app, '/health');
    assert.equal(res.status, 200);
    assert.deepStrictEqual(res.body, { status: 'ok' });
  });
});

describe('API routes', () => {
  it('GET /api returns welcome message', async () => {
    const app = express();
    app.use('/api', router);
    const res = await request(app, '/api');
    assert.equal(res.status, 200);
    assert.ok(res.body.message);
  });
});

import { describe, it, before, after } from 'node:test';
import assert from 'node:assert/strict';
import http from 'node:http';
import express from 'express';
import cors from 'cors';
import { router } from '../src/routes/index.js';

let server;
let baseUrl;

function fetch(path) {
  return new Promise((resolve, reject) => {
    http.get(`${baseUrl}${path}`, (res) => {
      let body = '';
      res.on('data', (chunk) => { body += chunk; });
      res.on('end', () => resolve({ status: res.statusCode, body: JSON.parse(body) }));
    }).on('error', reject);
  });
}

describe('Integration: /api/users', () => {
  before(() => {
    return new Promise((resolve) => {
      const app = express();
      app.use(cors());
      app.use(express.json());
      app.use('/api', router);
      app.get('/health', (req, res) => res.json({ status: 'ok' }));
      server = app.listen(0, () => {
        baseUrl = `http://127.0.0.1:${server.address().port}`;
        resolve();
      });
    });
  });

  after(() => {
    return new Promise((resolve) => server.close(resolve));
  });

  it('GET /api/users returns 200 and an array', async () => {
    const res = await fetch('/api/users');
    assert.equal(res.status, 200);
    assert.ok(Array.isArray(res.body));
    assert.ok(res.body.length > 0);
  });

  it('GET /health returns 200', async () => {
    const res = await fetch('/health');
    assert.equal(res.status, 200);
    assert.deepStrictEqual(res.body, { status: 'ok' });
  });
});
